    def calculate_total_capacity(node, graph):
        """Calculate total capacity for a node by summing capacities of all descendant ports"""
        total = 0
        # BFS/DFS to find all ports under this node
        stack = [node]
        while stack:
            current = stack.pop()
            for neighbor in graph.neighbors(current):
                if 'EK_PORT' in graph.nodes[neighbor]['type']:
                    total += graph.nodes[neighbor].get('physical_capacity_bps', 0)
                else:
                    stack.append(neighbor)
        return total

